// INCORRECT: Each process gets a separate local cache.
CacheModule.register({
  ttl: 60,
});

correct:
// CORRECT: Production cache uses an external store.
CacheModule.registerAsync({
  inject: [ConfigService],
  useFactory: (config: ConfigService) => ({
    stores: [createKeyv(config.getOrThrow("REDIS_URL"))],
  }),
});

// CORRECT: Structured logs include job and dependency context.
this.logger.error("job failed", {
  jobId: job.id,
  queue: job.queueName,
  cause: error instanceof Error ? error.message : "unknown",
});

incorrect:
// INCORRECT: A retry can send the same email twice.
@Process("send-email")
async send(job: Job<EmailJob>) {
  await this.mailer.send(job.data);
}

correct:
// CORRECT: The processor is retry-safe.
@Process("send-email")
async send(job: Job<EmailJob>) {
  if (await this.outbox.wasProcessed(job.id)) {
    return;
  }

  await this.mailer.send(job.data);
  await this.outbox.markProcessed(job.id);
}

incorrect:
// INCORRECT: Every app replica will run this cron.
@Cron(CronExpression.EVERY_DAY_AT_MIDNIGHT)
async billCustomers() {
  await this.billing.run();
}

correct:
// CORRECT: A distributed lock prevents duplicate cron side effects.
@Cron(CronExpression.EVERY_DAY_AT_MIDNIGHT)
async billCustomers() {
  await this.lock.runOnce("billing:daily", async () => {
    await this.billing.run();
  });
}

incorrect:
// INCORRECT: The connected microservice does not inherit global pipes or guards.
app.connectMicroservice<MicroserviceOptions>({
  transport: Transport.TCP,
});
await app.startAllMicroservices();

correct:
// CORRECT: The microservice inherits the main app's cross-cutting config.
app.connectMicroservice<MicroserviceOptions>(
  {
    transport: Transport.TCP,
  },
  { inheritAppConfig: true },
);
await app.startAllMicroservices();

incorrect:
// INCORRECT: HTTP exceptions do not model RPC failures.
@MessagePattern({ cmd: "charge" })
async charge(data: ChargeMessage) {
  if (!data.accountId) {
    throw new BadRequestException("accountId is required");
  }
  return this.billing.charge(data);
}

correct:
// CORRECT: Message handlers use transport-aware exceptions.
@MessagePattern({ cmd: "charge" })
async charge(data: ChargeMessage) {
  if (!data.accountId) {
    throw new RpcException({ code: "INVALID_PAYLOAD" });
  }
  return this.billing.charge(data);
}
